 10→interface PostCardProps {
 11→  title: string;
 12→  bodyPreview: string;
 13→  authorName: string;
 14→  authorAvatar?: string | null;
 15→  authorBadge?: 'legend' | 'og' | null;
 16→  bannerImage?: string | null;
 17→  postType?: string;
 18→  readingTime?: string;
 19→  likeCount: number;
 20→  commentCount: number;
 21→  bookmarkCount?: number;
 22→  isLiked?: boolean;
 23→  isBookmarked?: boolean;
 24→  userReaction?: string | null;
 25→  onPress?: () => void;
 26→  onLike?: () => void;
 27→  onComment?: () => void;
 28→  onBookmark?: () => void;
 29→  onRepost?: () => void;
 30→  onReact?: (type: string) => void;
 31→  onAuthorPress?: () => void;
 32→}
 33→
 34→export function PostCard({
 35→  title,
 36→  bodyPreview,
 37→  authorName,
 38→  authorAvatar,
 39→  authorBadge,
 40→  bannerImage,
 41→  postType,
 42→  readingTime,
 43→  likeCount,
 44→  commentCount,
 45→  bookmarkCount,
 46→  isLiked,
 47→  isBookmarked,
 48→  userReaction,
 49→  onPress,
 50→  onLike,
 51→  onComment,
 52→  onBookmark,
 53→  onRepost,
 54→  onReact,
 55→  onAuthorPress,
 56→}: PostCardProps) {
 57→  const {colors} = useTheme();
 58→  const s = shadows(colors);
 59→
 60→  return (
 61→    <Pressable
 62→      onPress={onPress}
 63→      style={({pressed}) => [
 64→        styles.card,
 65→        {
 66→          backgroundColor: colors.bgCard,
 67→          borderColor: colors.borderCard,
 68→        },
 69→        s.card,
 70→        pressed && styles.pressed,
 71→      ]}>
 72→      {bannerImage ? (
 73→        <Image
 74→          source={{uri: bannerImage}}
 75→          style={styles.banner}
 76→          resizeMode="cover"
 77→        />
 78→      ) : null}
 79→
 80→      <View style={styles.content}>
 81→        {/* Author row */}
 82→        <View style={styles.authorRow}>
 83→          <Pressable
 84→            style={styles.authorTouchable}
 85→            onPress={onAuthorPress}
 86→            disabled={!onAuthorPress}>
 87→            <Avatar uri={authorAvatar} name={authorName} size={22} badge={authorBadge} />
 88→            <Text
 89→              style={[styles.authorName, {color: colors.textSecondary}]}
 90→              numberOfLines={1}>
 91→              {authorName}
 92→            </Text>
 93→            {authorBadge ? <BadgeCheckIcon size={14} badge={authorBadge} /> : null}
 94→          </Pressable>
 95→          {postType && postType !== 'journal' ? (
 96→            <View style={[styles.typePill, {backgroundColor: colors.bgPill}]}>
 97→              <Text style={[styles.typeText, {color: colors.accentSage}]}>
 98→                {postType}
 99→              </Text>
100→            </View>
101→          ) : null}
102→          {readingTime ? (
103→            <View style={[styles.typePill, {backgroundColor: colors.bgPill}]}>
104→              <Text style={[styles.typeText, {color: colors.accentSage}]}>
105→                {readingTime}
106→              </Text>
107→            </View>
108→          ) : null}
109→        </View>
110→
111→        {/* Title */}
112→        <Text
113→          style={[styles.title, {color: colors.textHeading}]}
114→          numberOfLines={2}>
115→          {title}
116→        </Text>
117→
118→        {/* Body preview */}
119→        {bodyPreview ? (
120→          <Text
121→            style={[styles.body, {color: colors.textBody}]}
122→            numberOfLines={3}>
123→            {bodyPreview}
124→          </Text>
125→        ) : null}
126→      </View>
127→
128→      <ActionBar
129→        likeCount={likeCount}
130→        commentCount={commentCount}
131→        bookmarkCount={bookmarkCount}
132→        isLiked={isLiked}
133→        isBookmarked={isBookmarked}
134→        userReaction={userReaction}
135→        onLike={onLike}
136→        onComment={onComment}
137→        onBookmark={onBookmark}
138→        onRepost={onRepost}
139→        onReact={onReact}
140→      />
141→    </Pressable>
142→  );
143→}
