219→
220→  async getFreedomWallWeeks(limit = 8, token?: string): Promise<{ data?: FreedomWeek[] }> {
221→    const params = new URLSearchParams();
222→    params.set('limit', String(limit));
223→
224→    return apiRequest<{ data?: FreedomWeek[] }>(`/freedom-wall/weeks?${params.toString()}`, {
225→      method: 'GET',
226→      headers: {
227→        ...authHeaders(token),
228→      },
229→    });
230→  },
231→
232→  async getCurrentFreedomWallWeek(token?: string): Promise<{ data?: FreedomWeek }> {
233→    return apiRequest<{ data?: FreedomWeek }>('/freedom-wall/current', {
234→      method: 'GET',
235→      headers: {
236→        ...authHeaders(token),
237→      },
238→    });
239→  },
240→
241→  async getFreedomWallItems(
242→    weekId: string,
243→    options: { limit?: number; cursor?: string; types?: string[] | string } = {},
244→    token?: string,
245→  ): Promise<CursorPage<FreedomItem>> {
246→    const params = new URLSearchParams();
247→    params.set('limit', String(options.limit ?? 200));
248→    if (options.cursor) {
249→      params.set('cursor', options.cursor);
250→    }
251→    if (Array.isArray(options.types) && options.types.length > 0) {
252→      params.set('types', options.types.join(','));
253→    } else if (typeof options.types === 'string' && options.types.trim().length > 0) {
254→      params.set('types', options.types.trim());
255→    }
256→
257→    return apiRequest<CursorPage<FreedomItem>>(
258→      `/freedom-wall/${encodeURIComponent(weekId)}/items?${params.toString()}`,
259→      {
260→        method: 'GET',
261→        headers: {
262→          ...authHeaders(token),
263→        },
264→      },
265→    );
266→  },
267→
268→  async getUniversePosts(
269→    viewport: { minX: number; maxX: number; minY: number; maxY: number },
270→    limit = 200,
271→  ): Promise<{ data?: UniversePost[] }> {
272→    const params = new URLSearchParams();
273→    params.set('minX', String(viewport.minX));
274→    params.set('maxX', String(viewport.maxX));
275→    params.set('minY', String(viewport.minY));
276→    params.set('maxY', String(viewport.maxY));
277→    params.set('limit', String(limit));
278→
279→    return apiRequest<{ data?: UniversePost[] }>(`/universe/posts?${params.toString()}`, {
280→      method: 'GET',
281→    });
282→  },
283→
284→  async getUserByUsername(username: string): Promise<UserDataResponse> {
285→    return apiRequest<UserDataResponse>(
286→      `/user/${encodeURIComponent(username)}`,
287→      {method: 'GET'},
288→    );
289→  },
290→
291→  async getRelatedPosts(journalId: string): Promise<{data: JournalItem[]}> {
292→    return apiRequest<{data: JournalItem[]}>(
293→      `/journal/${encodeURIComponent(journalId)}/related`,
294→      {method: 'GET'},
295→    );
296→  },
297→
298→  async getUserJournals(token: string, userId: string, cursor: string | null, limit = 10): Promise<CursorPage<JournalItem>> {
299→    const params = new URLSearchParams();
300→    params.set('limit', String(limit));
301→    params.set('userId', userId);
302→    if (cursor) params.set('before', cursor);
303→    return apiRequest<CursorPage<JournalItem>>(`/userJournals?${params.toString()}`, {
304→      method: 'GET',
305→      headers: {Authorization: `Bearer ${token}`},
306→    });
307→  },
308→
309→  async saveJournal(token: string, payload: { title: string; plainText: string; html?: string }): Promise<{ message?: string }> {
310→    const formData = new FormData();
311→
312→    const lexicalPayload = {
313→      root: {
314→        children: [
315→          {
316→            type: 'paragraph',
317→            children: [
318→              {
319→                type: 'text',
320→                text: payload.plainText,
321→                detail: 0,
322→                format: 0,
323→                mode: 'normal',
324→                style: '',
325→                version: 1,
326→              },
327→            ],
328→            direction: null,
329→            format: '',
330→            indent: 0,
331→            version: 1,
332→          },
333→        ],
334→        direction: null,
335→        format: '',
336→        indent: 0,
337→        type: 'root',
338→        version: 1,
339→      },
340→    };
341→
342→    formData.append('title', payload.title);
343→    formData.append('content', JSON.stringify(lexicalPayload));
344→    formData.append('post_type', 'text');
345→
346→    return apiRequest<{ message?: string }>('/save-journal', {
347→      method: 'POST',
348→      headers: {
349→        ...authHeaders(token),
350→      },
351→      body: formData,
352→      timeoutMs: 30000,
353→      retries: 0,
354→    });
355→  },
356→};
