 44→  NativeStackScreenProps<RootStackParamList>
 45→>;
 46→
 47→const PAGE_SIZE = 10;
 48→
 49→const QUICK_ACTIONS = [
 50→  {key: 'all', label: 'All'},
 51→  {key: 'journal', label: 'Journals'},
 52→  {key: 'canvas', label: 'Canvas'},
 53→  {key: 'freedom_wall', label: 'Freedom Wall'},
 54→  {key: 'universe', label: 'Universe'},
 55→] as const;
 56→
 57→export function HomeFeedScreen({navigation}: Props) {
 58→  const {user, session} = useAuth();
 59→  const {colors} = useTheme();
 60→  const token = session?.access_token ?? '';
 61→  const [refreshing, setRefreshing] = useState(false);
 62→  const [activeFilter, setActiveFilter] = useState('all');
 63→  const [commentModal, setCommentModal] = useState<{postId: string; receiverId?: string; commentCount: number} | null>(null);
 64→  const [repostModal, setRepostModal] = useState<{journalId: string; title?: string; authorName?: string; authorAvatar?: string} | null>(null);
 65→
 66→  const feedQuery = useInfiniteQuery({
 67→    queryKey: ['feed', user?.id],
 68→    queryFn: ({pageParam}) =>
 69→      mobileApi.getJournals(pageParam ?? null, PAGE_SIZE, user?.id),
 70→    initialPageParam: null as string | null,
 71→    getNextPageParam: lastPage => getNextCursor(lastPage, PAGE_SIZE),
 72→  });
 73→
 74→  const reactionMutation = useMutation({
 75→    mutationFn: async ({
 76→      journalId,
 77→      receiverId,
 78→      reactionType,
 79→    }: {
 80→      journalId: string;
 81→      receiverId: string;
 82→      reactionType: string;
 83→    }) => {
 84→      if (!token) throw new Error('Please log in to react.');
 85→      return socialApi.toggleReaction(token, {journalId, receiverId, reactionType});
 86→    },
 87→    onMutate: async ({journalId, reactionType}) => {
 88→      await queryClient.cancelQueries({queryKey: ['feed']});
 89→      const prev = queryClient.getQueryData<{pages: CursorPage<JournalItem>[]}>(
 90→        ['feed', user?.id],
 91→      );
 92→      if (prev) {
 93→        queryClient.setQueryData<{pages: CursorPage<JournalItem>[]}>(
 94→          ['feed', user?.id],
 95→          old => {
 96→            if (!old) return old;
 97→            return {
 98→              ...old,
 99→              pages: old.pages.map(page => ({
100→                ...page,
101→                data: page.data.map(item => {
102→                  if (item.id !== journalId) return item;
103→                  const removing = item.user_reaction === reactionType;
104→                  const currentCount =
105→                    (item.reaction_count?.[0]?.count ??
106→                      item.like_count?.[0]?.count ??
107→                      item.likes_count ??
108→                      0) as number;
109→                  const delta = removing ? -1 : item.user_reaction ? 0 : 1;
110→                  return {
111→                    ...item,
112→                    user_reaction: removing ? null : reactionType,
113→                    has_liked: removing ? false : true,
114→                    like_count: [{count: Math.max(0, currentCount + delta)}],
115→                  };
116→                }),
117→              })),
118→            };
119→          },
120→        );
121→      }
122→      return {prev};
123→    },
124→    onError: (_err, _vars, context) => {
125→      if (context?.prev) {
126→        queryClient.setQueryData(['feed', user?.id], context.prev);
127→      }
128→    },
129→    onSettled: () => {
130→      queryClient.invalidateQueries({queryKey: ['feed']});
131→    },
132→  });
133→
134→  const bookmarkMutation = useBookmarkMutation(token, ['feed', user?.id]);
135→
136→  const handleReact = (journalId: string, receiverId: string, reactionType: string) => {
137→    if (!token) return;
138→    reactionMutation.mutate({journalId, receiverId, reactionType});
139→  };
140→
141→  const handleComment = (journalId: string, receiverId?: string, commentCount?: number) => {
142→    setCommentModal({postId: journalId, receiverId, commentCount: commentCount ?? 0});
143→  };
144→
