 35→export function RepostModal({
 36→  visible,
 37→  sourceJournalId,
 38→  title,
 39→  authorName,
 40→  authorAvatar,
 41→  onClose,
 42→}: RepostModalProps) {
 43→  const {session} = useAuth();
 44→  const {colors} = useTheme();
 45→  const token = session?.access_token ?? '';
 46→  const [caption, setCaption] = useState('');
 47→  const [submitting, setSubmitting] = useState(false);
 48→
 49→  const handleRepost = async () => {
 50→    if (!token) {
 51→      Alert.alert('Error', 'Please log in to repost.');
 52→      return;
 53→    }
 54→    setSubmitting(true);
 55→    try {
 56→      await socialApi.createRepost(token, {
 57→        sourceJournalId,
 58→        caption: caption.trim() || undefined,
 59→      });
 60→      queryClient.invalidateQueries({queryKey: ['feed']});
 61→      queryClient.invalidateQueries({queryKey: ['profileWritings']});
 62→      setCaption('');
 63→      onClose();
 64→      Alert.alert('Reposted', 'Post was reposted to your feed.');
 65→    } catch (e) {
 66→      Alert.alert('Repost failed', e instanceof Error ? e.message : 'Could not repost. Please try again.');
 67→    } finally {
 68→      setSubmitting(false);
 69→    }
 70→  };
 71→
 72→  const displayTitle = title
 73→    ? title.length > 80 ? title.slice(0, 80) + '...' : title
 74→    : 'Untitled Post';
